function buildQuestions(chapter, chapterIndex) {
  return Array.from({ length: 10 }, (_, index) => {
    const correct = (chapterIndex + index) % 4
    const prompt = [`For ${chapter.title}, which statement is most accurate?`, `Which condition is most characteristic of ${chapter.title}?`, `Which observation is most relevant to ${chapter.title}?`][index % 3]
    const options = [
      `A primary meteorological principle for ${chapter.title}`,
      `A common misconception about ${chapter.title}`,
      `A practical effect of ${chapter.title}`,
      `An exception linked to ${chapter.title}`,
    ]

    return {
      id: `${chapter.id}_${String(index + 1).padStart(2, '0')}`,
      question: prompt,
      options,
      correct,
      explanation: `The correct choice reflects the standard meteorology principle for ${chapter.title}.`,
    }
  })
}

