  // ── MET09: Stability ──
  met09: [
    { id: 'met09_01', question: 'DALR = 9.8 C, ELR = 6.8 C; atmosphere is', options: ['Stable', 'Unstable', 'Indifferent', 'Neutral'], correct: 0, explanation: 'ELR < DALR means atmosphere is stable for dry air.' },
    { id: 'met09_02', question: 'SALR = 5.5 C, ELR = 4.5 C; atmosphere is', options: ['Unstable', 'Stable', 'Indifferent', 'Neutral'], correct: 1, explanation: 'ELR < SALR means saturated air is stable.' },
    { id: 'met09_03', question: 'DALR > ELR > SALR', options: ['Conditionally stable', 'Latently stable', 'Potentially stable', 'Absolutely unstable'], correct: 0, explanation: 'Conditional instability when ELR lies between SALR and DALR.' },
    { id: 'met09_04', question: 'Dry air is unstable when', options: ['ELR=DALR', 'ELR>DALR', 'ELR<DALR', 'ELR=0'], correct: 1, explanation: 'Dry air unstable when ELR exceeds DALR.' },
    { id: 'met09_05', question: 'If ELR less than SALR, atmosphere is', options: ['Absolutely unstable', 'Conditionally stable', 'Absolutely stable', 'Neutral'], correct: 2, explanation: 'ELR < SALR < DALR makes atmosphere absolutely stable.' },
    { id: 'met09_06', question: 'DALR is approximately', options: ['5 C/km', '15 C/km', '10 C/km', '6.5 C/km'], correct: 2, explanation: 'DALR ~9.8 C/km, rounded to 10.' },
    { id: 'met09_07', question: 'SALR at mean sea level is about', options: ['10 C/km', '5 C/km', '5 F/km', '8 C/km'], correct: 1, explanation: 'SALR averages about 5-6 C/km at MSL.' },
    { id: 'met09_08', question: 'Inversion in atmosphere indicates', options: ['Stability', 'Instability', 'Neutrality', 'Mixing'], correct: 0, explanation: 'Inversion is a very stable layer.' },
    { id: 'met09_09', question: 'Inversion is ___ Lapse Rate', options: ['Positive', 'Negative', 'Neutral', 'Zero'], correct: 1, explanation: 'Inversion has negative lapse rate (temp rises with height).' },
    { id: 'met09_10', question: 'SALR approaches DALR', options: ['At 0 C', 'At -15 F', 'At -40 C', 'At 100 C'], correct: 2, explanation: 'At very low temperatures saturation vapour is small so SALR approaches DALR.' },
    { id: 'met09_11', question: 'Saturated air is unstable if', options: ['SALR=ELR', 'SALR<ELR', 'SALR>ELR', 'SALR=0'], correct: 1, explanation: 'Saturated air unstable when ELR exceeds SALR.' },
    { id: 'met09_12', question: 'If ELR = SALR = DALR the atmosphere is', options: ['Stable', 'Instable', 'Indifferent', 'Neutral'], correct: 2, explanation: 'Equal lapse rates give neutral/indifferent stability.' },
    { id: 'met09_13', question: 'DALR means', options: ['Rate of temperature fall in unsaturated parcel rising adiabatically', 'Rate temp falls with height', 'Rate saturated air cools', 'Rate of pressure fall'], correct: 0, explanation: 'DALR is dry adiabatic cooling rate of rising unsaturated parcel.' },
    { id: 'met09_14', question: 'Surface temp 30 C. Using DALR temperature at 2 km is', options: ['18 C', '10 C', '42 C', '20 C'], correct: 1, explanation: 'DALR ~10 C/km; 30-20 = 10 C at 2 km.' },
    { id: 'met09_15', question: 'An Isothermal atmosphere is', options: ['Stable', 'Unstable', 'Neutral', 'Variable'], correct: 0, explanation: 'Isothermal layer (ELR=0) is very stable.' },
    { id: 'met09_16', question: 'Environmental LR can be more than DALR', options: ['True', 'False', 'Never', 'Sometimes'], correct: 0, explanation: 'Super-adiabatic layers can exist (ELR > DALR), absolutely unstable.' },
    { id: 'met09_17', question: 'Process determining vertical distribution of temperature', options: ['Adiabatic', 'Isothermal', 'Isentropic', 'Conductive'], correct: 0, explanation: 'Adiabatic processes largely set vertical T profile.' },
    { id: 'met09_18', question: 'Rise in temperature with height is', options: ['Inversion', 'Lapse', 'Normal', 'Isothermal'], correct: 0, explanation: 'Rising T with height is inversion.' },
    { id: 'met09_19', question: 'Dry air at 35 C surface rising 1 km adiabatically attains temperature', options: ['29 C', '25 C', '45 C', '20 C'], correct: 1, explanation: '35 - 10 (DALR) = 25 C.' },
    { id: 'met09_20', question: 'Inversion is common in', options: ['Post Monsoon', 'Monsoon', 'Winters', 'Summer'], correct: 2, explanation: 'Surface radiation inversions are most common in winter.' },
  ],
 
